import {
	Tabs,
	HeaderPage,
	BackgroundForm,
	DeclarationsForm,
	GeneralInformationForm,
} from "Components/Appraisal";

// import { useEffect, useRef } from "react";
// import { Status, Wrapper }   from "@googlemaps/react-wrapper";

const tabs = [
	{
		title        : "Antecedentes",
		Tab          : BackgroundForm,
		sectionTitle : "1.1 Antecedentes",
	},
	{
		title        : "Información General del Inmueble",
		Tab          : GeneralInformationForm,
		sectionTitle : "1.2 Información General del Inmueble",
	},
	{
		title        : "Declaraciones y Advertencias",
		Tab          : DeclarationsForm,
		sectionTitle : "1.3 Declaraciones y Advertencias",
	},
];

const AppraisalSection1 = ({
	delegations : {
		onSubmit,
		hookForm,
		isLoading,
	},
}) => {

	const { formState : { isDirty } } = hookForm;

	return (
		<div id="AppraisalSection1">
			<HeaderPage
				currentIndex={[0, 0]}
				section="body"
				isDirty={isDirty}
				onSubmit={onSubmit}
				isSubmitingData={isLoading}
			/>

			<Tabs
				tabs={tabs}
				hookForm={hookForm}
				onSubmit={onSubmit}
				isSubmitingData={isLoading}
			 />
		</div>
	);
};

