import { useMemo }               from "react";
import { useForm, useFormState } from "react-hook-form";
import { useParams }             from "react-router-dom";

import { deepAccessObj, getTime, isValidArray } from "Helpers";
import { useHandlerMutation }                   from "Helpers/Hooks";
import section1Api                              from "Store/api/section1Api";
import AppraisalSection1                        from "./AppraisalSection1";

const DEFAULT_FETCH_DATA = {
	 appraise : {
		page_one : { background : {}, general_information : {}, statement_warning : {} },
	},
};

const AppraisalSection1Container = ({ appraise }) => {

	const { id : appraiseId } = useParams();

	// ------------> RTK-Q <---------------
	const [ editApprasial, { isLoading  : isLoadingMutation } ] = useHandlerMutation({ toastName : "apprasialCRUD" });

	const { background, general_information, statement_warning } = appraise.page_one;

	// ------------> useHookForm <---------------
	const defaultValues  = useMemo(() => ({
		background,
		general_information : {
			...general_information,
			alignment_date    : getTime(general_information?.alignment_date),
			contract_date     : getTime(general_information?.contract_date),
			date_judgment     : getTime(general_information?.date_judgment),
			deed_date         : getTime(general_information?.deed_date),
			date_other_source : getTime(general_information?.date_other_source),
		},
		statement_warning,
		long_dmsh : {
			degree     : "",
			minutes    : "",
			seconds    : "",
			hemisphere : "",
		},
		lat_dmsh : {
			degree     : "",
			minutes    : "",
			seconds    : "",
			hemisphere : "",
		},
	}), []);

	const hookForm = useForm({ defaultValues });

	const { control, handleSubmit } = hookForm;

	const { dirtyFields } = useFormState({ control });

	// ------------> submitData <---------------
	const getValidDateToSubmit = (dateToSubmit, defaultDate, key) => {
		if (isDirtyDate(key)) {
			if (isFlatPickerDate(dateToSubmit)) {
				return  dateToSubmit[0];
			}

			return undefined;
		}
		if (isInvalidDate(defaultDate)) {
			return undefined;
		}

		return defaultDate;
	};

	const isFlatPickerDate = (dateToSubmit) => isValidArray(dateToSubmit);

	const isDirtyDate = (key) => deepAccessObj(key, dirtyFields);

	const isInvalidDate = (defaultDate) => (defaultDate === null || defaultDate?.length === 0);

	const deleteDmshGeoReferences = (dataToSubmit) => {
		delete dataToSubmit["long_dmsh"];
		delete dataToSubmit["lat_dmsh"];
	};

	const buildDataToSubmit = (formData) => {
		const {
			alignment_date,
			contract_date,
			date_judgment,
			deed_date,
			date_other_source,
		} = formData.general_information;


		const dataToSubmit = {
			...formData,
			general_information : {
				...formData.general_information,
				alignment_date    : getValidDateToSubmit(alignment_date, general_information?.alignment_date, "general_information.alignment_date"),
				contract_date     : getValidDateToSubmit(contract_date, general_information?.contract_date, "general_information.contract_date"),
				date_judgment     : getValidDateToSubmit(date_judgment, general_information?.date_judgment, "general_information.date_judgment"),
				deed_date         : getValidDateToSubmit(deed_date, general_information?.deed_date, "general_information.deed_date"),
				date_other_source : getValidDateToSubmit(date_other_source, general_information?.date_other_source, "general_information.date_other_source"),
			},
		};

		deleteDmshGeoReferences(dataToSubmit);

		return dataToSubmit;
	};

	const onSubmit = handleSubmit(async (formData) => {
		const dataToSubmit = buildDataToSubmit(formData);

		await editApprasial({
			module : `appraisals/page-one/${appraiseId}`,
			method : "PUT",
			data   : dataToSubmit,
			tags   : ["appraisals", "apprasial_details"],
		});
	});

	return (
		<AppraisalSection1
			delegations={{
				onSubmit,
				hookForm,
				isLoading : isLoadingMutation,
			}}
		/>
	);
};

const  AppraisalHOCPageFetcher = (Wrapped) => () => {
	const { id : appraiseId } = useParams();

	const { data = DEFAULT_FETCH_DATA, isFetching  } = section1Api.useGetSection1Query(appraiseId);


	if (isFetching) {
		return  <>Cargando Formulario...</>;
	}

	const { appraise } = data;

	return <Wrapped appraise={appraise} />;
};

export default AppraisalHOCPageFetcher(AppraisalSection1Container);
